  "BIOS 4814": {"name": "Special Topics", "hours": 4, "description": "This designation enables the School of Biology to provide new lecture courses dealing with areas of current interest in biological science."},
  "BIOS 4835": {"name": "Special Topics", "hours": 3, "description": "Special Topics offered by the School of Biological Sciences."},
