  "BMED 8811": {"name": "Special Topics", "hours": 1, "description": "Topics of current interest in biomedical engineering."},
  "BMED 8813": {"name": "Special Topics", "hours": 3, "description": "Topics of current interest in biomedical engineering."},
  "BMED 8843": {"name": "Special Topics", "hours": 3, "description": "Special Topics."},
  "BMED 8901": {"name": "Special Problems", "hours": 1, "description": "Individual studies and/or experimental investigations of problems of current interest in bioengineering."},
