  "MATH 0399": {"name": "Support for Precalculus", "hours": 2, "description": "Practicum for Learning Support students enrolled in MATH 1113 (Precalculus)."},
  "MATH 0999": {"name": "Support for College Algebra", "hours": 2, "description": "This Learning Support course provides corequisite support in mathematics for students enrolled in MATH 1111 \u2013 College Algebra. Topics will parallel topics being studied in MATH 1111 and the course will provide support for the essential quantitative skills needed to be successful in MATH 1111. Taken with MATH 1111, this course provides an in-depth study of the properties of algebraic, exponential and logarithmic functions as needed for calculus. Emphasis is on using algebraic and graphical techniques for solving problems involving linear, quadratic, piece-wise defined, rational, polynomial, exponential and logarithmic functions."},
  "MATH 1111": {"name": "College Algebra", "hours": 4, "description": "This course provides an in-depth study of the properties of algebraic, exponential and logarithmic functions as needed for calculus. Emphasis is on using algebraic and graphical techniques for solving problems involving linear, quadratic, piece-wise defined, rational, polynomial, exponential and logarithmic functions."},
  "MATH 1113": {"name": "Pre-calculus", "hours": 4, "description": "This course is an intensive study of the basic functions needed for the study of calculus. Topics include algebraic, functional, and graphical techniques for solving problems with algebraic, exponential, logarithmic, and trigonometric functions and their inverses. May only be used for degree credit with departmental approval."},
  "MATH 11X3": {"name": "Transfer Precalculus", "hours": 3, "description": ""},
  "MATH 1499": {"name": "Support for Differential Calculus", "hours": 1, "description": "This corequisite studio course provides extra precalculus support for students enrolled in Math 1551, Differential Calculus."},
  "MATH 1550": {"name": "Introduction to Differential Calculus", "hours": 3, "description": "An introduction to differential calculus including applications and the underlying theory of limits for functions and sequences. Credit not awarded for both MATH 1550 and MATH 1501, MATH 1551, or MATH 1503."},
  "MATH 1551": {"name": "Differential Calculus", "hours": 2, "description": "Differential calculus including applications and the underlying theory of limits for functions and sequences. Credit not awarded for both MATH 1551 and MATH 1501, MATH 1503, or MATH 1550."},
  "MATH 1552": {"name": "Integral Calculus", "hours": 4, "description": "Integral calculus: Definite and indefinite integrals, techniques of integration, improper integrals, infinite series, applications. Credit not awarded for both MATH 1552 and MATH 1502, MATH 1504, MATH 1512 or MATH 1555."},
  "MATH 1553": {"name": "Introduction to Linear Algebra", "hours": 2, "description": "An introduction to linear alegbra including eigenvalues and eigenvectors, applications to linear systems, least squares. Credit not awarded for both MATH 1553 and MATH 1522, MATH 1502, MATH 1504, MATH 1512, MATH 1554 or MATH 1564."},
  "MATH 1554": {"name": "Linear Algebra", "hours": 4, "description": "Linear algebra eigenvalues, eigenvectors, applications to linear systems, least squares, diagnolization, quadratic forms."},
  "MATH 1564": {"name": "Linear Algebra with Abstract Vector Spaces", "hours": 4, "description": "This is an intensive first course in linear algebra including the theories of linear transformations and abstract vector spaces. Credit not awarded for both MATH 1564 and MATH 1553, MATH 1554, MATH 1522, MATH 1502, MATH 1504 or MATH 1512."},
  "MATH 1711": {"name": "Finite Mathematics", "hours": 4, "description": "Linear equations, matrices, linear programming, sets and counting, probability and statistics."},
  "MATH 1712": {"name": "Survey of Calculus", "hours": 4, "description": "Techniques of differentiation, integration, application of integration to probability and statistics, multidimensional calculus. Credit not allowed for both MATH 1712 and 1501."},
  "MATH 17X1": {"name": "Transfer Finite Math", "hours": 3, "description": ""},
  "MATH 17X2": {"name": "Transfer Survey-Calc", "hours": 3, "description": ""},
