  "MATH 2106": {"name": "Foundations of Mathematical Proof", "hours": 3, "description": "An introduction to proofs in advanced mathematics, intended as a transition to upper division courses including Abstract Algebra I and Analysis I."},
  "MATH 2550": {"name": "Introduction to Multivariable Calculus", "hours": 2, "description": "Vectors in three dimensions, curves in space, functions of several variables, partial derivatives, optimization, integration of functions of several variables. Vector Calculus not covered. Credit will not be awarded for both MATH 2550 and MATH 2605 or MATH 2401 or MATH 2551 or MATH 1555."},
  "MATH 2551": {"name": "Multivariable Calculus", "hours": 4, "description": "Multivariable calculus: Linear approximation and Taylor's theorems, Lagrange multiples and constrained optimization, multiple integration and vector analysis including the theorems of Green, Gauss, and Stokes. Credit will not be awarded for both MATH 2551 and MATH 2401 or MATH 2411 or MATH 2561."},
  "MATH 2552": {"name": "Differential Equations", "hours": 4, "description": "Methods for obtaining numerical and analytic solutions of elementary differential equations. Applications are also discussed with an emphasis on modeling. Credit not awarded for both MATH 2552 and MATH 2403 or MATH 2413 or MATH 2562."},
  "MATH 2561": {"name": "Honors Multivariable Calculus", "hours": 4, "description": "The topics covered parallel those of MATH 2551 with a somewhat more intensive and rigorous treatment. Credit not awarded for both MATH 2561 and MATH 2401 or MATH 2411 or MATH 2551."},
  "MATH 2562": {"name": "Honors Differential Equations", "hours": 4, "description": "The topics covered parallel those of MATH 2552 with a somewhat more intensive and rigorous treatment."},
  "MATH 2603": {"name": "Introduction to Discrete Mathematics", "hours": 4, "description": "Mathematical logic and proof, mathematical induction, counting methods, recurrence relations, algorithms and complexity, graph theory and graph algorithms. Credit not awarded for both MATH 2603 and MATH 2602."},
