  "NEUR 2000": {"name": "Principles of Neuroscience for non-majors", "hours": 3, "description": "Students will learn fundamental principles and methods in neuroscience from problem-based study of the neural substrates of animal behavior. For Non-Neuroscience Majors."},
  "NEUR 2000R": {"name": "NEUR 2000 Recitation", "hours": 0, "description": "Recitation for NEUR 2000."},
  "NEUR 2001": {"name": "Principles in Neuroscience", "hours": 4, "description": "Students will learn fundamental principles and methods in neuroscience from problem-based study of te neural subtrates of animal behavior."},
  "NEUR 2001R": {"name": "Introduction to Neuroscience Recitation", "hours": 0, "description": "Recitation for NEUR 2001."},
  "NEUR 2010": {"name": "Principles of Neuroscience for Majors", "hours": 3, "description": "Students will learn fundamental principles and methods in neuroscience through problem-based study of the neural substrates of animal behavior. For Non-Neuroscience Majors."},
  "NEUR 2010L": {"name": "Principles of Neuroscience Lab", "hours": 1, "description": "Students will learn fundamental techniques and methods in neuroscience from activities, experiments, and problem-based study of the neural substrates of animal behavior. For Neuroscience Majors."},
