  "NEUR 3001": {"name": "Cell and Molecular Neuroscience", "hours": 3, "description": "An overview of principles and techniques in cell and molecular neuroscience: neuron excitability, synaptic transmission, learning and memory to basic mechanisms of neurological diseases."},
  "NEUR 3002": {"name": "Systems, Networks, and Computational Neuroscience", "hours": 3, "description": "This course explores how complex functions emerge from neural systems and networks, emphasizing computational approaches to network operations, and modeling the mechanisms underlying nervous system communication and organization."},
  "NEUR 3003": {"name": "Neuroscience of Behavior", "hours": 3, "description": "This course examines the biological basis of psychology. Behavioral Neuroscience is an interdisciplinary science that aims to investigate the interaction between brain and behavior. Credit will not be awarded for PSYC 4020 and NEUR 3003."},
  "NEUR 3010": {"name": "Methods in Neuroscience", "hours": 3, "description": "The course is focused on understanding how information about brain and nervous system function can be determined from a wide range of experimental and data analysis techniques."},
  "NEUR 3801": {"name": "Special Topics in Neuroscience", "hours": 1, "description": ""},
  "NEUR 3802": {"name": "Special Topics in Neuroscience", "hours": 2, "description": ""},
  "NEUR 3803": {"name": "Special Topics in Neuroscience", "hours": 3, "description": ""},
  "NEUR 3804": {"name": "Special Topics in Neuroscience", "hours": 4, "description": ""},
