  "NEUR 3832": {"name": "Special Topics lab", "hours": 2, "description": "Special Topics lab."},
  "NEUR 3XXX": {"name": "Neuroscience Elective", "hours": 1, "description": ""},
  "NEUR 4001": {"name": "Neuroscience Research Project", "hours": 4, "description": "Focused on multidisciplinary perspectives in neuroscience, this course requires that students utilize and apply the skills and knowledge developed over the course of their major."},
  "NEUR 4100": {"name": "Neurodevelopment", "hours": 3, "description": "An introduction to the principles of developmental biology of the nervous system, more specifically how neurons and born and connect to one another to form a nervous system."},
  "NEUR 4200": {"name": "Functional Neuroanatomy", "hours": 3, "description": "The purpose of this course is to learn the functional organization of nervous systems with an emphasis on mammalian central and peripheral neuroanatomy."},
  "NEUR 4238": {"name": "Ion Channels in Health and Disease", "hours": 3, "description": "We will examine the role of ion channels in diverse human diseases and learn basic biophysical properties, structure, normal physiology and pharmacology of ion channels."},
  "NEUR 4300": {"name": "Neuroscience of Memory", "hours": 3, "description": "How does the nervous system support learning and memory? How does memory guide behavior and decisions? Course emphasizes mammalian brain, but students consider fundamental mechanisms."},
  "NEUR 4400": {"name": "Neuroendocrinology", "hours": 3, "description": "An introduction to study of the interactions of the nervous and endocrine systems, specifically covering how the brain regulates the hormonal activity in the body."},
  "NEUR 4601": {"name": "Neuroscience Thesis Research", "hours": 4, "description": "A course in which selected students conduct original research under the direction of a faculty member."},
  "NEUR 4696": {"name": "Undergraduate Teaching Assistantship", "hours": 0, "description": "Neuroscience teaching assistantship for pay under the guidance of a faculty member. Permit only. Note: This course cannot count toward Neuroscience Electives or Free Electives."},
  "NEUR 4697": {"name": "Undergraduate Teaching Experience", "hours": 3, "description": "An introduction to teaching neuroscience for undergraduate teaching assistants, with a focus on effective teaching, active engagement of students, and development of innovative classroom activities."},
  "NEUR 4698": {"name": "Undergraduate Research Assistantship", "hours": 1, "description": "Independent research conducted under the guidance of a faculty member."},
  "NEUR 4699": {"name": "Undergraduate Research", "hours": 1, "description": "Independent research conducted under the guidance of a faculty member."},
  "NEUR 4730": {"name": "Neuroplasticity in Atypical Development", "hours": 3, "description": "Explores how the human brain adapts to atypical developmental conditions, integrating behavioral and neurobiological perspectives on plasticity in blindness, deafness, limb loss, ASD, and schizophrenia."},
  "NEUR 4740": {"name": "Neuroethics", "hours": 3, "description": "This course considers the implications of neuroscience research on culture, society, the legal system, and on how individuals conceive of their nature as human beings."},
  "NEUR 4753": {"name": "Frontiers in Neuroengineering", "hours": 3, "description": "Neuroengineering issues related to measurement and manipulation of the nervous system for basic scientific discovery and treatment of neurological disorders."},
