  "NEUR 6001": {"name": "Principles of Neuroscience and Neurotechnology", "hours": 3, "description": "This course provides an overview of the underlying biological processes that give rise to neural activity."},
  "NEUR 6002": {"name": "Neurophysiology", "hours": 3, "description": "The course will focus on function and adaptations of muscular and neural systems. Interactions among the various systems and their plasticity will be emphasized."},
  "NEUR 6003": {"name": "Cognitive Neuroscience", "hours": 3, "description": "This course examines the foundations of Cognitive Neuroscience, including the biological mechanisms underlying cognition, the dominant theories, and the experimental techniques."},
  "NEUR 6730": {"name": "Neuroplasticity in Atypical Development", "hours": 3, "description": "Explores how the human brain adapts to atypical developmental conditions, integrating behavioral and neurobiological perspectives on plasticity in blindness, deafness, limb loss, ASD, and schizophrenia."},
