  "PHYS 1111K": {"name": "Introductory Physics I", "hours": 4, "description": "An introductory course which will include mechanics (kinematics, dynamics, work and energy, momentum and collisions, and rotational motion and statics), and will include thermodynamics and waves. Elementary algebra and trigonometry will be used."},
  "PHYS 11X1": {"name": "Transfer Non-Calc Phys I", "hours": 1, "description": ""},
  "PHYS 11X2": {"name": "Transfer Non-Calc PhysII", "hours": 1, "description": ""},
  "PHYS 1XXX": {"name": "Physics Elective", "hours": 1, "description": ""},
  "PHYS 2021": {"name": "The Solar System", "hours": 3, "description": "This course covers Ancient and Renaissance astronomy, gravity, sky phenomena, telescopes, and the solar system."},
  "PHYS 2022": {"name": "Stars, Galaxies, and the Universe", "hours": 3, "description": "This course covers optics, telescopes, stellar characteristics and evolution, galaxies, the universe, and the big bang. Physics topics include mechanics, optics, atomic physics, nuclear physics, and relativity."},
  "PHYS 2210": {"name": "Introduction to Astrophysics", "hours": 3, "description": "This course provides an overview of modern astrophysics including stars, galaxies, black holes and other dense stellar remnants, and the physics of the expanding Universe."},
  "PHYS 2211": {"name": "Principles of Physics I", "hours": 4, "description": "An introductory course which will include mechanics (kinematics, dynamics, work and energy, momentum and collisions, and rotational motion and statics), and may also include oscillations and computational methods. This is a calculus-based course."},
  "PHYS 2212": {"name": "Principles of Physics II", "hours": 4, "description": "An introductory course which will include electrostatics, electric current and circuits, electromagnetism, and may also include light and computational methods. This is a calculus-based course."},
  "PHYS 2213": {"name": "Introduction to Modern Physics", "hours": 3, "description": "A survey of twentieth century physics. Developments of several branches of physics up to their present frontiers, including historical and philosophical perspectives."},
  "PHYS 2231": {"name": "Honors Physics I", "hours": 5, "description": "Parallels introductory Physics I (PHYS 2211). Some topics treated in more depth or more extensively. A rigorous physics foundation requiring demonstrated competence in mathematics."},
  "PHYS 2232": {"name": "Honors Physics II", "hours": 5, "description": "Parallels introductory Physics II (PHYS 2212). Some topics treated in more depth or more extensively. No modern physics content. A rigorous physics foundation requiring demonstrated competence in mathematics."},
  "PHYS 2303": {"name": "Vibrations and Waves", "hours": 3, "description": "An introduction to oscillating and wave systems in physics, illustrated with examples drawn from different physical settings (e.g., mechanics, electromagnetism, quantum mechanics)."},
  "PHYS 2304": {"name": "Modern Physics", "hours": 3, "description": "A first course in special relativity and quantum physics, including both fundamental concepts (e.g., wave-particle duality) and applications (e.g., radioactivity). Credit not awarded for both PHYS 2304 and PHYS 2213."},
  "PHYS 25X1": {"name": "Transfer Physics I", "hours": 4, "description": ""},
  "PHYS 2698": {"name": "Undergraduate Research Assistantship", "hours": 1, "description": "Independent research conducted under the guidance of a faculty member."},
  "PHYS 2699": {"name": "Undergraduate Research", "hours": 1, "description": "Independent research conducted under the guidance of a faculty member."},
  "PHYS 2750": {"name": "Physics of the Weather", "hours": 3, "description": "An introductory treatment applying basic physical laws to understanding weather phenomena. Crosslisted with EAS 2750."},
  "PHYS 2802": {"name": "Special Topics", "hours": 2, "description": "Courses in special topics of current interest in physics are presented from time to time."},
  "PHYS 2803": {"name": "Special Topics", "hours": 3, "description": "Courses in special topics of current interest in physics are presented from time to time."},
  "PHYS 2901": {"name": "Special Problems", "hours": 1, "description": "Courses involving special problems in physics are offered from time to time."},
  "PHYS 2902": {"name": "Special Problems", "hours": 1, "description": "Courses involving special problems in physics are offered from time to time."},
