  "POL 1101": {"name": "Government of the U.S.", "hours": 3, "description": "American political institutions, constitution, processes, and behavior."},
  "PSYC 1101": {"name": "Introduction to General Psychology", "hours": 3, "description": "A broad survey of the major topics in psychology including, but not limited to, research methodology, biological and social factors influencing behavior, development, learning, memory, personality, and abnormal."},
  "PSYC 1XXX": {"name": "Psychology Elective", "hours": 1, "description": ""},
  "PSYC 2005": {"name": "Exploring Multicultural Identities", "hours": 3, "description": "This course explores multicultural identities and key multicultural competencies needed to succeed in a global and international society."},
  "PSYC 2012": {"name": "Introduction to Research Methods", "hours": 3, "description": "Introduction to methods used in conducting research on human behavior. Experimental research emphasized, but course covers other methods and some statistics."},
  "PSYC 2015": {"name": "Research Methods", "hours": 4, "description": "Introduction to methods used in conducting research on human behavior. Experimental research emphasized, but course covers other methods and some statistics."},
  "PSYC 2020": {"name": "Psychological Statistics", "hours": 4, "description": "Introduction to probability and statistics as applied to psychological data. Tests for means, variances, correlation, ANVOA, and regression. Credit not allowed for both PSYC 2020 and PSYC 6022."},
  "PSYC 2103": {"name": "Human Development Over the Life Span", "hours": 3, "description": "An introductory, non-laboratory based examination of human development across the lifespan with an emphasis on typical patterns of physical, cognitive, and social development."},
  "PSYC 2130": {"name": "Introduction to Educational Psychology", "hours": 3, "description": "Introduction to Educational Psychology applies the basic principles of child and adolescent development to the study of teaching and learning."},
  "PSYC 2210": {"name": "Social Psychology", "hours": 3, "description": "Consideration of the behavior of individuals in social contexts, including interpersonal and group settings."},
  "PSYC 2220": {"name": "Industrial/Organizational Psychology", "hours": 3, "description": "An introduction to industrial/organizational psychology providing an overview of behavior in the workplace and psychology applied in industrial and organizational settings."},
  "PSYC 2230": {"name": "Abnormal Psychology", "hours": 3, "description": "This course surveys the spectrum of psychiatric disorders (symptoms, epidemiology, etiology, and treatment) and provides a perspective on adaptive functioning and psychological resilience."},
  "PSYC 2240": {"name": "Personality Theory", "hours": 3, "description": "Introduction to major approaches to personality theory."},
